Create a component that renders uploaded file attachments above message text. Images get inline thumbnails, non-image files get styled chips matching the existing `FileChipBar` component styling.

## File to Create

`apps/client/src/layers/features/chat/ui/message/FileAttachmentList.tsx`

```typescript
import { File as FileIcon, FileText, FileCode, FileSpreadsheet, FileImage } from 'lucide-react';
import type { ParsedFile } from '../../lib/parse-file-prefix';
import { useAppStore } from '@/layers/shared/model';

/** Map file extension to a lucide icon component. */
function getFileIcon(filename: string) {
  const ext = filename.split('.').pop()?.toLowerCase() ?? '';
  switch (ext) {
    case 'pdf':
    case 'doc':
    case 'docx':
    case 'txt':
    case 'md':
      return FileText;
    case 'ts':
    case 'tsx':
    case 'js':
    case 'jsx':
    case 'py':
    case 'rs':
    case 'go':
    case 'java':
    case 'c':
    case 'cpp':
    case 'h':
    case 'json':
    case 'yaml':
    case 'yml':
    case 'toml':
    case 'xml':
    case 'html':
    case 'css':
    case 'sh':
      return FileCode;
    case 'csv':
    case 'xls':
    case 'xlsx':
      return FileSpreadsheet;
    case 'png':
    case 'jpg':
    case 'jpeg':
    case 'gif':
    case 'webp':
    case 'svg':
      return FileImage;
    default:
      return FileIcon;
  }
}

interface FileAttachmentListProps {
  files: ParsedFile[];
}

/** Renders uploaded file attachments — thumbnails for images, chips for documents. */
export function FileAttachmentList({ files }: FileAttachmentListProps) {
  const selectedCwd = useAppStore((s) => s.selectedCwd);

  if (files.length === 0) return null;

  const imageFiles = files.filter((f) => f.isImage);
  const otherFiles = files.filter((f) => !f.isImage);

  return (
    <div className="mb-1.5 space-y-1.5">
      {/* Image thumbnails */}
      {imageFiles.length > 0 && (
        <div className="flex flex-wrap gap-1.5">
          {imageFiles.map((file) => (
            <div
              key={file.path}
              className="overflow-hidden rounded-lg border border-border/50"
            >
              <img
                src={`/api/uploads/${encodeURIComponent(file.path.split('/').pop() ?? '')}?cwd=${encodeURIComponent(selectedCwd ?? '')}`}
                alt={file.displayName}
                className="max-h-[120px] max-w-[200px] object-contain"
                loading="lazy"
              />
            </div>
          ))}
        </div>
      )}

      {/* Non-image file chips */}
      {otherFiles.length > 0 && (
        <div className="flex flex-wrap gap-1.5">
          {otherFiles.map((file) => {
            const Icon = getFileIcon(file.displayName);
            return (
              <div
                key={file.path}
                className="bg-muted flex items-center gap-1 rounded-md px-2 py-1 text-xs"
              >
                <Icon className="text-muted-foreground size-3 shrink-0" />
                <span className="max-w-40 truncate">{file.displayName}</span>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
```

## Styling Rationale

- File chips use `bg-muted rounded-md px-2 py-1 text-xs` — identical to `FileChipBar` pre-send chips (see `apps/client/src/layers/features/chat/ui/FileChipBar.tsx` line 22 for reference)
- Image thumbnails constrained to `max-h-[120px] max-w-[200px]` — matches Claude.ai convention
- `object-contain` preserves aspect ratio
- `rounded-lg border border-border/50` gives subtle framing to images
- `loading="lazy"` defers offscreen image loading
- `mb-1.5` separates attachments from message text below

